 1	import * as React from 'react';
 2	
 3	import { V1VirtualMachine, V1VirtualMachineInstance } from '@kubevirt-ui/kubevirt-api/kubevirt';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { getVolumes } from '@kubevirt-utils/resources/vm';
 6	import { Label } from '@patternfly/react-core';
 7	
 8	type HotplugLabelProps = {
 9	  diskName: string;
10	  vm: V1VirtualMachine;
11	  vmi?: V1VirtualMachineInstance;
12	};
13	
14	export const HotplugLabel: React.FC<HotplugLabelProps> = ({ diskName, vm, vmi }) => {
15	  const { t } = useKubevirtTranslation();
16	
17	  const hotplugText = React.useMemo(() => {
18	    const volumeStatus = vmi?.status?.volumeStatus?.find(
19	      (volStatus) => volStatus.name === diskName,
20	    );
21	
22	    const vmVolume = getVolumes(vm)?.find((vol) => vol?.name === diskName);
23	    if (!vmVolume && vmi) {
24	      return t('AutoDetach Hotplug');
25	    }
26	    if (
27	      volumeStatus?.hotplugVolume ||
28	      vmVolume?.dataVolume?.hotpluggable ||
29	      vmVolume?.persistentVolumeClaim?.hotpluggable
30	    ) {
31	      return t('Persistent Hotplug');
32	    }
33	    return null;
34	  }, [diskName, t, vm, vmi]);
35	
36	  if (!hotplugText) {
37	    return null;
38	  }
39	
40	  return (
41	    <Label color="purple" variant="filled">
42	      {hotplugText}
43	    </Label>
44	  );
45	};

